@startuml
package "com" {
    package iluwatar {
        frame dependency <<Folder>> {
            folder injection <<Rectangle>> {
                class SimpleWizard {
                    - tobacco : OldTobyTobacco
                    + SimpleWizard()
                    + smoke()
                }

                class AdvancedWizard {
                    - tobacco : Tobacco
                    + AdvancedWizard(tobacco : Tobacco)
                    + smoke()
                }

                class GuiceWizard {
                    - tobacco : Tobacco
                    + GuiceWizard(tobacco : Tobacco)
                    + smoke()
                }

                interface Wizard {
                    + smoke()
                }

                abstract class App {
                    + App()
                    + main(args : String[])
                }

                abstract class RivendellTobacco {
                    + RivendellTobacco()
                }

                class OldTobyTobacco {
                    + OldTobyTobacco()
                }

                class SecondBreakfastTobacco {
                    + SecondBreakfastTobacco()
                }

                abstract class Tobacco {
                    + Tobacco()
                    + smoke(wizard : Wizard)
                }

                ' Relationships for Wizards to Interface/Abstract Class
                AdvancedWizard ..|> Wizard
                GuiceWizard ..|> Wizard

                ' Relationship between concrete wizard and simple implementation 
                note right of SimpleWizard::tobacco\nSimpleWizard uses specific type directly.\nNo constructor parameter needed here. endnote
